reference_solution:
def lookup_word(dictionary, word):
    low = 0
    high = len(dictionary) - 1
    while low <= high:
        mid = (low + high) // 2
        if dictionary[mid] == word:
            return mid
        elif dictionary[mid] < word:
            low = mid + 1
        else:
            high = mid - 1
    return -1

unit_tests:
import unittest

class TestSolution(unittest.TestCase):
    def test_word_in_middle(self):
        self.assertEqual(lookup_word(["apple", "banana", "cherry", "date", "fig"], "cherry"), 2)

    def test_word_not_found(self):
        self.assertEqual(lookup_word(["apple", "banana", "cherry"], "grape"), -1)

    def test_empty_dictionary(self):
        self.assertEqual(lookup_word([], "apple"), -1)

    def test_hidden_word_at_start(self):
        self.assertEqual(lookup_word(["apple", "banana", "cherry"], "apple"), 0)

    def test_hidden_word_at_end(self):
        self.assertEqual(lookup_word(["apple", "banana", "cherry"], "cherry"), 2)

    def test_hidden_single_element_found(self):
        self.assertEqual(lookup_word(["apple"], "apple"), 0)

    def test_hidden_single_element_not_found(self):
        self.assertEqual(lookup_word(["apple"], "banana"), -1)

    def test_hidden_missing_word_between_entries(self):
        self.assertEqual(lookup_word(["ant", "bat", "cat", "dog", "elk", "fox", "gnu"], "cow"), -1)

    def test_hidden_two_elements_find_first(self):
        self.assertEqual(lookup_word(["alpha", "beta"], "alpha"), 0)

    def test_hidden_two_elements_find_second(self):
        self.assertEqual(lookup_word(["alpha", "beta"], "beta"), 1)

    def test_hidden_word_before_all(self):
        self.assertEqual(lookup_word(["banana", "cherry", "date"], "apple"), -1)

    def test_hidden_word_after_all(self):
        self.assertEqual(lookup_word(["apple", "banana", "cherry"], "zebra"), -1)

if __name__ == '__main__':
    unittest.main()
